pages.page_css:
.event-page .i2g-winners { background: #fff8e1; border: 1px solid #e6c200; border-left: 5px solid #daa900;
  border-radius: 6px; padding: 0.75rem 1.1rem; margin: 0.5rem 0 1rem; }
.event-page .i2g-winners ul { margin: 0.4rem 0 0 1.2rem; }
.event-page .i2g-winners li { margin: 0.25rem 0; }
.event-page .i2g-schedule ul { list-style: none; padding-left: 0; }
.event-page .i2g-schedule li { padding: 0.3rem 0; border-bottom: 1px solid #eee; }
.event-page .i2g-info { display: flex; flex-wrap: wrap; gap: 0.5rem; margin: 0.75rem 0 1.5rem; }
.event-page .cms-project-table-caption { color: #555; font-size: 0.85rem; margin: 0 0 0.4rem; }

.event-page .i2g-table-wrap { overflow-x: auto; margin: 0.4rem 0 1.5rem; }
.event-page .i2g-award-table { width: 100%; border-collapse: collapse; font-size: 0.9rem; }
.event-page .i2g-award-table th { background: #002856; color: #fff; padding: 0.5rem 0.6rem; border: 1px solid #002856; text-align: left; }
.event-page .i2g-award-table td { padding: 0.45rem 0.6rem; border: 1px solid #e0e0e0; }
.event-page .i2g-award-table tr.w-cap td { background: rgba(218, 169, 0, 0.18); }
.event-page .i2g-award-table tr.w-cee td { background: rgba(153, 217, 217, 0.32); }
.event-page .i2g-award-table tr.w-cse td { background: rgba(0, 40, 86, 0.06); }

